import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void multipleDuplicatesInMiddle() {
        // [1,2,2,2,3] â€” first 2 is at index 1
        assertEquals(1, new Solution().firstOccurrence(new int[]{1, 2, 2, 2, 3}, 2));
    }

    @Test
    void allElementsSame() {
        // [1,1,1] â€” first 1 is at index 0
        assertEquals(0, new Solution().firstOccurrence(new int[]{1, 1, 1}, 1));
    }

    @Test
    void targetAtLastPosition() {
        // [1,2,2,2,3] â€” first 3 is at index 4
        assertEquals(4, new Solution().firstOccurrence(new int[]{1, 2, 2, 2, 3}, 3));
    }

    @Test
    void targetNotPresent() {
        assertEquals(-1, new Solution().firstOccurrence(new int[]{1, 2, 3}, 5));
    }

    @Test
    void emptyArray() {
        assertEquals(-1, new Solution().firstOccurrence(new int[]{}, 1));
    }

    @Test
    void noDuplicatesTargetFound() {
        // Works correctly on arrays without duplicates too
        assertEquals(2, new Solution().firstOccurrence(new int[]{10, 20, 30, 40, 50}, 30));
    }

    @Test
    void targetAppearsAtStart() {
        // Duplicates spanning from index 0
        assertEquals(0, new Solution().firstOccurrence(new int[]{5, 5, 5, 7, 9}, 5));
    }
}
